 646→app.get('/share/u/:username/image', async (req, res) => {
 647→    const { username } = req.params;
 648→
 649→    // Serve from cache if available
 650→    const cached = getShareImageCached(`profile:${username}`);
 651→    if (cached) {
 652→        res.set('Content-Type', 'image/jpeg');
 653→        res.set('Cache-Control', 'public, max-age=3600');
 654→        return res.send(cached);
 655→    }
 656→
 657→    await ensureShareFonts();
 658→
 659→    try {
 660→        const result = await getUserByUsernameService(username);
 661→        const user = result?.userData?.[0];
 662→        if (!user) {
 663→            return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 664→        }
 665→
 666→        const displayName = normalizeWhitespace(user.name) || username;
 667→        const handle = `@${normalizeWhitespace(user.username || username)}`;
 668→        const bio = toPreviewText(user.bio || '', 120);
 669→
 670→        // ── Fetch background image ──
 671→        let bgBuffer = null;
 672→        const bgStyle = user.background || {};
 673→        const bgImageMatch = typeof bgStyle.backgroundImage === 'string'
 674→            ? bgStyle.backgroundImage.match(/url\(["']?([^"')]+)["']?\)/)
 675→            : null;
 676→        const bgImageUrl = bgImageMatch?.[1];
 677→
 678→        if (bgImageUrl) {
 679→            const bgEval = evaluateShareImageCandidate(bgImageUrl);
 680→            if (bgEval.ok && bgEval.resolvedUrl) {
 681→                try {
 682→                    const remote = await fetchRemoteImageBuffer(bgEval.resolvedUrl);
 683→                    bgBuffer = remote.buffer;
 684→                } catch { /* use fallback gradient */ }
 685→            }
 686→        }
 687→
 688→        // ── Base layer: background or dark gradient ──
 689→        let baseLayer;
 690→        if (bgBuffer) {
 691→            baseLayer = await sharp(bgBuffer, { limitInputPixels: 60_000_000 })
 692→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, { fit: 'cover' })
 693→                .toBuffer();
 694→        } else {
 695→            // Use profile's solid background color if available, otherwise dark fallback
 696→            const solidColor = (typeof bgStyle.background === 'string' && /^#[0-9a-fA-F]{3,8}$/.test(bgStyle.background.trim()))
 697→                ? bgStyle.background.trim()
 698→                : null;
 699→            const gradientSvg = solidColor
 700→                ? `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 701→                    <rect width="100%" height="100%" fill="${solidColor}"/>
 702→                </svg>`
 703→                : `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 704→                    <defs><linearGradient id="g" x1="0%" y1="0%" x2="100%" y2="100%">
 705→                        <stop offset="0%" stop-color="#1a1a2e"/>
 706→                        <stop offset="100%" stop-color="#16213e"/>
 707→                    </linearGradient></defs>
 708→                    <rect width="100%" height="100%" fill="url(#g)"/>
 709→                </svg>`;
 710→            baseLayer = await sharp(Buffer.from(gradientSvg))
 711→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT)
 712→                .png()
 713→                .toBuffer();
 714→        }
 715→
 716→        // ── Dark overlay for text readability ──
 717→        const overlaySvg = `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 718→            <rect width="100%" height="100%" fill="black" fill-opacity="0.55"/>
 719→        </svg>`;
 720→        const overlayBuffer = await sharp(Buffer.from(overlaySvg)).png().toBuffer();
 721→
 722→        // ── Circular avatar ──
 723→        let avatarComposite = null;
 724→        const avatarSize = 180;
 725→        const avatarUrl = user.image_url;
 726→        if (avatarUrl) {
 727→            const avatarEval = evaluateShareImageCandidate(avatarUrl);
 728→            if (avatarEval.ok && avatarEval.resolvedUrl) {
 729→                try {
 730→                    const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
 731→                    const circleMask = Buffer.from(
 732→                        `<svg width="${avatarSize}" height="${avatarSize}">
 733→                            <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
 734→                        </svg>`
 735→                    );
 736→                    const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
 737→                        .resize(avatarSize, avatarSize, { fit: 'cover' })
 738→                        .png()
 739→                        .toBuffer();
 740→                    const circularAvatar = await sharp(resizedAvatar)
 741→                        .composite([{ input: circleMask, blend: 'dest-in' }])
 742→                        .png()
 743→                        .toBuffer();
 744→                    avatarComposite = circularAvatar;
 745→                } catch { /* skip avatar */ }
 746→            }
 747→        }
 748→
 749→        // ── Compose all layers ──
 750→        const composites = [
 751→            { input: overlayBuffer, top: 0, left: 0 },
 752→        ];
 753→
 754→        if (avatarComposite) {
 755→            const avatarLeft = Math.round((DEFAULT_OG_IMAGE_WIDTH - avatarSize) / 2);
 756→            composites.push({ input: avatarComposite, top: 100, left: avatarLeft });
 757→        }
 758→
 759→        const finalImage = await sharp(baseLayer)
 760→            .composite(composites)
 761→            .jpeg({ quality: 82, mozjpeg: true })
 762→            .toBuffer();
 763→
 764→        setShareImageCached(`profile:${username}`, finalImage);
 765→        res.set('Content-Type', 'image/jpeg');
 766→        res.set('Cache-Control', 'public, max-age=3600');
 767→        return res.send(finalImage);
 768→    } catch (err) {
 769→        console.error('profile share image route error:', err?.message || err);
 770→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 771→    }
 772→});
