 848→    }
 849→
 850→    await ensureShareFonts();
 851→    const debugPayload = {
 852→        ok: false,
 853→        fallback: false,
 854→        journalId,
 855→        stage: 'start',
 856→        reason: '',
 857→        meta: {
 858→            imageCandidateSource: null,
