 883→            return fallbackWithReason('journal_not_found');
 884→        }
 885→
 886→        const shareMeta = buildShareMetaFromJournal(journal);
 887→        debugPayload.stage = 'candidate_extracted';
 888→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
 889→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
 890→
 891→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
 892→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
 893→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
 894→            return fallbackWithReason(candidateEvaluation.reason);
 895→        }
 896→
 897→        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
 898→        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
 899→            return fallbackWithReason('candidate_is_default_fallback');
 900→        }
 901→
 902→        debugPayload.stage = 'fetching_upstream';
 903→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
 904→        debugPayload.stage = 'upstream_loaded';
 905→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
 906→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
 907→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
 908→
 909→        debugPayload.stage = 'converting_image';
 910→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
 911→        debugPayload.stage = 'converted_image';
 912→        debugPayload.ok = true;
 913→        debugPayload.reason = 'ok';
 914→        debugPayload.meta.outputBytes = ogImageBuffer.length;
 915→
 916→        if (debugMode) {
 917→            return sendShareImageDebug(res, debugPayload);
 918→        }
 919→
 920→        setShareImageCached(`post:${journalId}`, ogImageBuffer);
 921→        res.set('Content-Type', 'image/jpeg');
 922→        res.set('Cache-Control', 'public, max-age=3600');
 923→        return res.send(ogImageBuffer);
 924→    } catch (err) {
