223→export const uploadJournalContentService = async(
224→    content,
225→    title,
226→    userId,
227→    remixSourceJournalId = null,
228→    isRemix = false,
229→    promptId = null
230→) =>{
231→    if(!userId){
232→        console.error('userId is undefined');
233→        throw {status: 400, error: 'userId is undefined'};
234→    }
235→
236→    const trimmedTitle = typeof title === 'string' ? title.trim() : '';
237→
238→    if(!trimmedTitle){
239→        console.error('title is missing!');
240→        throw {status: 400, error: 'title is missing!'};
241→    }
242→
243→    const shouldSaveRemixMetadata = Boolean(
244→        remixSourceJournalId
245→        && typeof remixSourceJournalId === 'string'
246→        && remixSourceJournalId.trim()
247→    );
248→    const normalizedIsRemix = shouldSaveRemixMetadata || String(isRemix).toLowerCase() === 'true';
249→
250→    if(!content){
251→        console.error('content is missing for text post!');
252→        throw {status: 400, error: 'content is missing for text post'};
253→    }
254→
255→    const parseData = parseTextContentSafely(content);
256→    if(!parseData){
257→        console.error('error while parsing text content data');
258→        throw {status: 400, error: 'error while parsing text content data'};
259→    }
260→
261→    const embeddingBody = parseData.wholeText || '';
262→    const preview_text = parseData.slicedText || '';
263→    const thumbnail_url = parseData.firstImage?.src || null;
264→    const reading_time = Math.ceil((embeddingBody.trim().split(/\s+/).length) / 150) || 1;
265→    const payload = {
266→        user_id: userId,
267→        title: trimmedTitle,
268→        post_type: POST_TYPE_TEXT,
269→        content: content,
270→        preview_text,
271→        thumbnail_url,
272→        reading_time,
273→    };
274→
275→    const embeddingResult = await GenerateEmbeddings(trimmedTitle, embeddingBody);
276→
277→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
278→        console.error('error while generating embeddings on a post!');
279→        throw {status: 400, error: 'error while generating embeddings on a post!'};
280→    }
281→
282→    const insertPayload = {
283→        ...payload,
284→        embeddings: embeddingResult
285→    };
286→
287→    if(normalizedIsRemix){
288→        insertPayload.is_remix = true;
289→    }
290→    if(shouldSaveRemixMetadata){
291→        insertPayload.remix_source_journal_id = remixSourceJournalId.trim();
292→    }
293→    if(promptId){
294→        const parsedPromptId = parseInt(promptId, 10);
295→        if(!isNaN(parsedPromptId)){
296→            insertPayload.prompt_id = parsedPromptId;
297→        }
298→    }
299→
300→    let insertResult = await supabase
301→    .from('journals')
302→    .insert(insertPayload)
303→    .select('id')
304→    .single();
305→
306→    let error = insertResult.error;
307→
308→    if(error){
309→        const missingRemixColumns = error?.message?.includes('is_remix') || error?.message?.includes('remix_source_journal_id');
310→        if(missingRemixColumns){
311→            const fallbackPayload = {
312→                ...payload,
313→                embeddings: embeddingResult
314→            };
315→
316→            insertResult = await supabase
317→            .from('journals')
318→            .insert(fallbackPayload)
319→            .select('id')
320→            .single();
321→            error = insertResult.error;
322→        }
323→    }
324→
325→    if(error){
326→        console.error('supabase error while uploading content:',error.message);
327→        throw {status: 500, error: 'supabase error while uploading content'};
328→    }
329→
330→    const journalId = insertResult.data?.id;
331→
332→    // Non-fatal: send mention notifications
333→    if(journalId){
334→        try {
335→            const mentionedUserIds = extractMentionUserIds(content);
336→            const filtered = mentionedUserIds
337→                .filter(id => id !== userId)
338→                .slice(0, 50);
339→
340→            if(filtered.length > 0){
341→                const notifRows = filtered.map(receiverId => ({
342→                    sender_id: userId,
343→                    receiver_id: receiverId,
344→                    type: 'mention',
345→                    journal_id: journalId,
346→                    read: false
347→                }));
348→
349→                const {error: notifError} = await supabase
350→                    .from('notifications')
351→                    .insert(notifRows);
352→
353→                if(notifError){
354→                    console.error('[mentions] new post: insert failed:', notifError.message);
355→                }
356→            }
357→        } catch (mentionErr) {
358→            console.error('[mentions] new post error:', mentionErr?.message || mentionErr);
359→        }
360→    }
361→
362→    // Non-fatal: record publish for writing streak
363→    let streakResult = null;
364→    try {
365→        const { recordPublishForStreak } = await import('./streakService.js');
366→        streakResult = await recordPublishForStreak(userId);
367→    } catch (streakErr) {
368→        console.error('non-fatal: streak record failed:', streakErr?.message || streakErr);
369→    }
370→
371→    return { success: true, streakResult };
372→}
