374→export const updateJournalService = async(content, title, journalId, userId) => {
375→    if(!journalId){
376→        console.error('journalid is undefined');
377→        throw {status: 400, error: 'journalId is undefined'}
378→    }
379→
380→    if(!userId){
381→        console.error('userId is undefined')
382→        throw({status: 400, error: 'userId is undefined'})
383→    }
384→
385→    const {data: existingJournal, error: existingJournalError} = await supabase
386→    .from('journals')
387→    .select('id, user_id, content, title, post_type')
388→    .eq('id', journalId)
389→    .eq('user_id', userId)
390→    .maybeSingle();
391→
392→    if(existingJournalError){
393→        console.error('failed to fetch existing journal for update', existingJournalError.message);
394→        throw {status: 500, error: 'failed to fetch existing journal for update'};
395→    }
396→
397→    if(!existingJournal){
398→        console.error('journal not found for update');
399→        throw {status: 404, error: 'journal not found for update'};
400→    }
401→
402→    const resolvedTitle = typeof title === 'string' && title.trim() ? title.trim() : existingJournal.title;
403→    if(!resolvedTitle){
404→        console.error('title is undefined');
405→        throw {status: 400, error: 'title is undefined'};
406→    }
407→
408→    let resolvedContent = existingJournal.content;
409→    if(typeof content === 'string' && content.trim()){
410→        resolvedContent = content;
411→    }
412→
413→    if(!resolvedContent){
414→        console.error('text content is missing for text post update');
415→        throw {status: 400, error: 'text content is missing for text post update'};
416→    }
417→
418→    const parseData = parseTextContentSafely(resolvedContent);
419→    if(!parseData){
420→        console.error('failed to parse text content for update');
421→        throw {status: 400, error: 'failed to parse text content for update'};
422→    }
423→
424→    const embeddingBody = parseData.wholeText || '';
425→    const preview_text = parseData.slicedText || '';
426→    const thumbnail_url = parseData.firstImage?.src || null;
427→    const reading_time = Math.ceil((embeddingBody.trim().split(/\s+/).length) / 150) || 1;
428→    const embeddings = await GenerateEmbeddings(resolvedTitle, embeddingBody);
429→
430→    if(!embeddings || !Array.isArray(embeddings) || embeddings.length === 0){
431→        console.error('failed to generate embeddings')
432→        throw {status: 400, error: 'failed to generate embeddings'};
433→    }
434→
435→    const journalData = {
436→        content: resolvedContent,
437→        title: resolvedTitle,
438→        post_type: POST_TYPE_TEXT,
439→        embeddings: embeddings,
440→        preview_text,
441→        thumbnail_url,
442→        reading_time,
443→    }
444→
445→    const {data, error} = await supabase
446→    .from('journals')
447→    .update(journalData)
448→    .eq('id', journalId)
449→    .eq('user_id', userId)
450→
451→    if(error){
452→        console.error('supabase error while uploading content:', error.message);
453→        throw{status: 500, error: 'supabase error while uploading content'};
454→    }
455→
456→    // Non-fatal: send mention notifications on edit
457→    try {
458→        const mentionedUserIds = extractMentionUserIds(resolvedContent);
459→        const filtered = mentionedUserIds
460→            .filter(id => id !== userId)
461→            .slice(0, 50);
462→
463→        // Remove old mention notifications for this journal to avoid duplicates
464→        const { error: deleteError } = await supabase
465→            .from('notifications')
466→            .delete()
467→            .eq('type', 'mention')
468→            .eq('journal_id', journalId);
469→
470→        if (deleteError) console.error('[mentions] edit: clear old failed:', deleteError.message);
471→
472→        if (filtered.length > 0) {
473→            const notifRows = filtered.map(receiverId => ({
474→                sender_id: userId,
475→                receiver_id: receiverId,
476→                type: 'mention',
477→                journal_id: journalId,
478→                read: false
479→            }));
480→
481→            const { error: notifError } = await supabase
482→                .from('notifications')
483→                .insert(notifRows);
484→
485→            if (notifError) console.error('[mentions] edit: insert failed:', notifError.message);
486→        }
487→    } catch (mentionErr) {
488→        console.error('[mentions] edit error:', mentionErr?.message || mentionErr);
489→    }
490→
491→    return true;
492→}
