  1→import supabase from "./supabase.js";
  2→
  3→// ── In-memory LRU cache for related posts ──
  4→const RELATED_CACHE_MAX = 200;
  5→const RELATED_CACHE_TTL_MS = 10 * 60 * 1000; // 10 minutes
  6→const _relatedCache = new Map();
  7→const getRelatedCached = (key) => {
  8→    const entry = _relatedCache.get(key);
  9→    if (!entry) return null;
 10→    if (Date.now() - entry.ts > RELATED_CACHE_TTL_MS) {
 11→        _relatedCache.delete(key);
 12→        return null;
 13→    }
 14→    // LRU refresh — move to end
 15→    _relatedCache.delete(key);
 16→    _relatedCache.set(key, entry);
 17→    return entry.value;
 18→};
 19→const setRelatedCached = (key, value) => {
 20→    if (_relatedCache.size >= RELATED_CACHE_MAX) {
 21→        const firstKey = _relatedCache.keys().next().value;
 22→        _relatedCache.delete(firstKey);
 23→    }
 24→    _relatedCache.set(key, { value, ts: Date.now() });
 25→};
 26→
 27→const CONFIDENCE_TIERS = {
 28→    high:   { threshold: 0.60, maxResults: 5, label: 'high' },
 29→    medium: { threshold: 0.48, maxResults: 3, label: 'medium' },
 30→    low:    { threshold: 0.38, maxResults: 2, label: 'low' },
 31→};
 32→
 33→let _dynamicFloorCache = { value: null, ts: 0 };
 34→const DYNAMIC_FLOOR_TTL_MS = 5 * 60 * 1000; // 5 minutes
 35→
 36→async function getDynamicFloor() {
 37→    if (_dynamicFloorCache.value !== null && Date.now() - _dynamicFloorCache.ts < DYNAMIC_FLOOR_TTL_MS) {
 38→        return _dynamicFloorCache.value;
 39→    }
 40→
 41→    const { count, error } = await supabase
 42→        .from('journals')
 43→        .select('id', { count: 'exact', head: true })
 44→        .eq('privacy', 'public')
 45→        .not('embeddings', 'is', null);
 46→
 47→    if (error) {
 48→        console.error('getDynamicFloor count error:', error.message);
 49→        return _dynamicFloorCache.value ?? 0.30;
 50→    }
 51→
 52→    let floor;
 53→    if (count < 500)  floor = 0.35;
 54→    else if (count < 2000) floor = 0.40;
 55→    else floor = 0.45;
 56→
 57→    _dynamicFloorCache = { value: floor, ts: Date.now() };
 58→    return floor;
 59→}
 60→
 61→function getConfidenceTier(topSimilarity) {
 62→    if (topSimilarity >= CONFIDENCE_TIERS.high.threshold)   return CONFIDENCE_TIERS.high;
 63→    if (topSimilarity >= CONFIDENCE_TIERS.medium.threshold) return CONFIDENCE_TIERS.medium;
 64→    if (topSimilarity >= CONFIDENCE_TIERS.low.threshold)    return CONFIDENCE_TIERS.low;
 65→    return null;
 66→}
 67→
 68→export async function getRelatedPostsService(journalId) {
 69→    const cached = getRelatedCached(journalId);
 70→    if (cached) return cached;
 71→
 72→    const dynamicFloor = await getDynamicFloor();
 73→
 74→    // First attempt with dynamic floor
 75→    let { data, error } = await supabase.rpc('find_related_posts', {
 76→        source_post_id: journalId,
 77→        match_count: 8,
 78→        similarity_floor: dynamicFloor,
 79→        recency_days: 365,
 80→    });
 81→
 82→    if (error) {
 83→        throw { status: 500, error: 'Failed to find related posts: ' + error.message };
 84→    }
 85→
 86→    // Fallback: if < 2 results, try with a lower floor
 87→    if (!data || data.length < 2) {
 88→        const lowerFloor = Math.max(dynamicFloor - 0.03, 0.30);
 89→        if (lowerFloor < dynamicFloor) {
 90→            const fallback = await supabase.rpc('find_related_posts', {
 91→                source_post_id: journalId,
 92→                match_count: 8,
 93→                similarity_floor: lowerFloor,
 94→                recency_days: 365,
 95→            });
 96→            if (!fallback.error && fallback.data && fallback.data.length >= 2) {
 97→                data = fallback.data;
 98→            }
 99→        }
100→    }
101→
102→    // Never show fewer than 2 results
103→    if (!data || data.length < 2) {
104→        return { posts: [], confidence: 'none', topSimilarity: 0 };
105→    }
106→
107→    const topSimilarity = data[0]?.semantic_similarity || 0;
108→    const tier = getConfidenceTier(topSimilarity);
109→
110→    if (!tier) {
111→        return { posts: [], confidence: 'none', topSimilarity };
112→    }
113→
114→    // Cap results by confidence tier
115→    const cappedPosts = data.slice(0, tier.maxResults);
116→
117→    // Ensure we still have at least 2 after capping
118→    if (cappedPosts.length < 2) {
119→        return { posts: [], confidence: 'none', topSimilarity };
120→    }
121→
122→    const result = {
123→        posts: cappedPosts,
124→        confidence: tier.label,
125→        topSimilarity,
126→    };
127→    setRelatedCached(journalId, result);
128→    return result;
129→}
