 1→import supabase from "./supabase.js"
 2→export const checkUserService = async(userId) =>{
 3→    if(!userId){
 4→        throw {status: 400, error: 'userId is undefined'}
 5→    }
 6→    const {data: userData, error: errorFetching} = await supabase
 7→    .from('users')
 8→    .select('id, onboarding_completed')
 9→    .eq('id', userId)
10→
11→    if(errorFetching){
12→        console.error('supabase error:', errorFetching.message)
13→        throw {status: 500, error: 'supabase error while checking user data'}
14→    }
15→
16→    return userData;
17→
18→}
