184→                if(updateProfileError){
185→                    console.error("supabase error while clearing profile media references:", updateProfileError.message);
186→                    throw {status: 500, error: "supabase error while clearing profile media references"};
187→                }
188→            }
189→        }
190→    }
191→
192→    return {
193→        deleted: true,
194→        bucket: bucket,
195→        path: normalizedPath,
