 90→const SHARE_IMAGE_CACHE_MAX = 200;
 91→const SHARE_IMAGE_CACHE_TTL_MS = 60 * 60 * 1000; // 1 hour
 92→const shareImageCache = new Map();
 93→const getShareImageCached = (key) => {
 94→    const entry = shareImageCache.get(key);
 95→    if (!entry) return null;
 96→    if (Date.now() - entry.ts > SHARE_IMAGE_CACHE_TTL_MS) {
 97→        shareImageCache.delete(key);
 98→        return null;
 99→    }
100→    // Move to end (LRU refresh)
101→    shareImageCache.delete(key);
102→    shareImageCache.set(key, entry);
103→    return entry.buf;
104→};
