557→app.use((req, res, next) => {
558→    metricsState.requests += 1;
559→    metricsState.inFlight += 1;
560→
561→    const startNs = process.hrtime.bigint();
562→    let byteCount = 0;
563→
564→    const originalWrite = res.write.bind(res);
565→    const originalEnd = res.end.bind(res);
566→
567→    res.write = (chunk, encoding, callback) => {
568→        if (chunk) {
569→            byteCount += Buffer.isBuffer(chunk)
570→                ? chunk.length
571→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
572→        }
573→        return originalWrite(chunk, encoding, callback);
574→    };
575→
576→    res.end = (chunk, encoding, callback) => {
577→        if (chunk) {
578→            byteCount += Buffer.isBuffer(chunk)
579→                ? chunk.length
580→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
581→        }
582→        return originalEnd(chunk, encoding, callback);
583→    };
584→
585→    res.on('finish', () => {
586→        metricsState.inFlight = Math.max(0, metricsState.inFlight - 1);
587→        metricsState.responses += 1;
588→        metricsState.bytesSent += byteCount;
589→
590→        const statusBucket = classifyStatusBucket(res.statusCode);
591→        metricsState.statusBuckets[statusBucket] += 1;
592→
593→        const durationMs = Number(process.hrtime.bigint() - startNs) / 1_000_000;
594→        const routeTemplate = req.route?.path
595→            ? `${req.baseUrl || ''}${req.route.path}`
596→            : req.path;
597→        const routeKey = `${req.method} ${canonicalizeMetricsPath(routeTemplate)}`;
598→
599→        let routeStat = metricsState.routeStats.get(routeKey);
600→        if (!routeStat) {
601→            if (metricsState.routeStats.size >= METRICS_ROUTE_LIMIT) {
602→                return;
603→            }
604→
605→            routeStat = {
606→                count: 0,
607→                totalDurationMs: 0,
608→                maxDurationMs: 0,
609→                bytesSent: 0,
610→                statusBuckets: { '2xx': 0, '3xx': 0, '4xx': 0, '5xx': 0, other: 0 },
611→            };
612→            metricsState.routeStats.set(routeKey, routeStat);
613→        }
614→
615→        routeStat.count += 1;
616→        routeStat.totalDurationMs += durationMs;
617→        routeStat.maxDurationMs = Math.max(routeStat.maxDurationMs, durationMs);
618→        routeStat.bytesSent += byteCount;
619→        routeStat.statusBuckets[statusBucket] += 1;
620→    });
621→
622→    next();
623→});
