 17→const normalizeInteractionFlag = (value) => {
 18→    if(typeof value === 'boolean') return value;
 19→    if(typeof value === 'string'){
 20→        const normalized = value.trim().toLowerCase();
 21→        if(normalized === 'true') return true;
 22→        if(normalized === 'false') return false;
 23→    }
 24→    if(typeof value === 'number'){
 25→        return value === 1;
 26→    }
 27→    return Boolean(value);
 28→};
